    .a16
    .i16
    ; Identical instruction, identical operand — only D changes. D=$0000 costs N cycles,
    ; D=$0001 costs N+1, because the penalty keys off DL != 0.
    rep #$30
    .a16
    .i16
    ldx #$0000
    lda #$0000
    tcd               ; DL = $00: no penalty
    jsr hv_begin
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080     ; baseline
    lda #$0001
    tcd               ; DL = $01: one extra cycle per access
    jsr hv_begin
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    lda $10,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$000A
    bcs :+
    jmp @fail1
  :
    cmp #$000F
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; direct-page +1 w penalty (DL != 0) not applied
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.02 — +1 p on indexed reads
; provenance: Documented (WDC datasheet; superfamicom.org cycle-count tables)
.proc test_a5_02
    .a16
    .i16
    ; lda $10FF,X with X=$01 crosses a page; with X=$00 it does not.
    ; The index must be 8-BIT: with a 16-bit index the cycle is unconditional, so the two
    ; measurements would be identical and the test would prove nothing.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$10
    .i8
    ldx #$00
    jsr hv_begin
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    sep #$10
    .i8
    ldx #$01          ; now every access crosses into the next page
    jsr hv_begin
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    lda a:$10FF,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$000A
    bcs :+
    jmp @fail1
  :
    cmp #$000F
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; indexed read did not pay the +1 p page-cross penalty
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.03 — Stores always pay +1 p
; provenance: Documented (WDC datasheet; superfamicom.org cycle-count tables)
.proc test_a5_03
    .a16
    .i16
    ; sta $10FF,X costs the same whether or not it crosses a page — stores always pay the
    ; cycle, so unlike the load in A5.02 there is no difference to find. Same 8-bit index.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$10
    .i8
    ldx #$00
    jsr hv_begin
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    sep #$10
    .i8
    ldx #$01          ; crosses a page, but must cost the same
    jsr hv_begin
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    sta a:$10FF,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$8000
    bcc :+
    eor #$FFFF
    inc a             ; negate: take the magnitude
  :
    cmp #$0003
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; indexed store timing changed with page crossing (it must not)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.04 — Decimal costs no cycles
; provenance: Documented (WDC datasheet)
.proc test_a5_04
    .a16
    .i16
    ; Same ADC, binary vs decimal. On the 65C02 decimal adds a cycle; on the 65816 it does not.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    cld
    jsr hv_begin
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080     ; baseline
    sep #$20
    .a8
    sed
    jsr hv_begin
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    clc
    adc #$01
    jsr hv_end
    sep #$20
    .a8
    cld               ; leave decimal before any further arithmetic
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$8000
    bcc :+
    eor #$FFFF
    inc a             ; negate: take the magnitude
  :
    cmp #$0003
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; decimal mode changed instruction timing (it must not on the 65816)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.05 — 16-bit RMW is +2
; provenance: Documented (WDC datasheet (corrects undisbeliever's table))
.proc test_a5_05
    .a16
    .i16
    ; ASL dp with m=1 vs m=0. The 16-bit form reads and writes an extra byte.
    rep #$30
    .a16
    .i16
    lda #$0000
    tcd
    sep #$20          ; 8-bit accumulator -> 8-bit RMW
    .a8
    jsr hv_begin
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    rep #$20          ; 16-bit accumulator -> 16-bit RMW
    .a16
    jsr hv_begin
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    asl $20
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$001E
    bcs :+
    jmp @fail1
  :
    cmp #$0023
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; 16-bit RMW is not +2 cycles over the 8-bit form
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.06 — Taken branch costs +1
; provenance: Documented (WDC datasheet)
.proc test_a5_06
    .a16
    .i16
    ; BCC taken vs not taken, same instruction, same target, one cycle apart.
    rep #$30
    .a16
    .i16
    sec               ; carry set -> BCC never taken
    jsr hv_begin
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    clc               ; carry clear -> BCC always taken
    jsr hv_begin
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    bcc *+2
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$000A
    bcs :+
    jmp @fail1
  :
    cmp #$000F
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; a taken branch did not cost one extra cycle
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A6.01 — BRK vectors natively
; provenance: Documented (WDC datasheet; SNESdev Wiki vectors)
.proc test_a6_01
    .a16
    .i16
    jmp @start
@handler:
    sep #$20
    .a8
    lda #$A5
    sta f:$7E0090     ; prove the handler actually ran
    rep #$30
    .a16
    .i16
    rti
@start:
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$00
    sta f:$7E0090
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler)
    sta a:V_BRK_VEC
    brk
    .byte $EA         ; BRK signature byte
    sep #$20
    .a8
    lda f:$7E0090
    cmp #$A5
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; native BRK did not reach the installed handler
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A6.02 — COP has its own vector
; provenance: Documented (WDC datasheet; SNESdev Wiki vectors)
.proc test_a6_02
    .a16
    .i16
    jmp @start
@handler:
    sep #$20
    .a8
    lda #$C0
    sta f:$7E0091
    rep #$30
    .a16
    .i16
    rti
@start:
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$00
    sta f:$7E0091
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler)
    sta a:V_COP_VEC
    ; Encoded as raw bytes rather than `cop #$00`. Immediate addressing on COP is accepted by
    ; recent ca65 git builds but rejected as an illegal addressing mode by the 2.19 release
    ; that CI installs from apt, and the ROM must assemble identically on both.
    .byte $02, $00    ; cop #$00
    sep #$20
    .a8
    lda f:$7E0091
    cmp #$C0
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; COP did not reach its own vector
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A6.03 — D cleared on interrupt
; provenance: Documented (WDC datasheet)
.proc test_a6_03
    .a16
    .i16
    jmp @start
@handler:
    sep #$20
    .a8
    php
    pla
    and #$08          ; D flag
    sta f:$7E0092
    rep #$30
    .a16
    .i16
    rti
@start:
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler)
    sta a:V_BRK_VEC
    sep #$20
    .a8
    lda #$FF
    sta f:$7E0092     ; poison, so 'handler never ran' cannot look like a pass
    sed
    brk
    .byte $EA
    cld
    sep #$20
    .a8
    lda f:$7E0092
    cmp #$00
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; D was not cleared on interrupt entry
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

