; A7.04 — Decimal V (golden)
; provenance: Contested (V in decimal mode is undefined; ares/bsnes/Mesen2 share a convention, which is agreement, not authority)
.proc test_a7_04
    .a16
    .i16
    ; SED; CLC; LDA #$99; ADC #$01 -> A=$00 with carry out. The A result is documented and
    ; is checked; V is NOT — it is captured and reported as a variant instead.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    sed
    clc
    lda #$99
    adc #$01
    cld
    php
    pla               ; stash P before the compare clobbers it
    sta f:$7E0060
    txa
    ; Re-run to get A back for the documented half of the check.
    sed
    clc
    lda #$99
    adc #$01
    cld
    cmp #$00
    beq :+
    jmp @fail1
  :
    ; Now branch on the observed V bit (P bit 6) and report it as a variant.
    lda f:$7E0060
    and #$40
    beq :+
    lda #$03          ; variant 1 = V observed SET   ((1<<1)|1)
    sta f:$7EE010
    jmp test_restore
    :
    lda #$05          ; variant 2 = V observed CLEAR ((2<<1)|1)
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; decimal ADC $99+$01 did not produce $00
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A8.01 — MVN fwd, A=$FFFF
; provenance: Documented (WDC datasheet)
.proc test_a8_01
    .a16
    .i16
    ; Copy 4 bytes within bank $7E using MVN; A must end at $FFFF.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$11
    sta f:$7E2000
    lda #$22
    sta f:$7E2001
    lda #$33
    sta f:$7E2002
    lda #$44
    sta f:$7E2003
    rep #$30
    .a16
    .i16
    ldx #$2000
    ldy #$2100
    lda #$0003        ; count-1
    mvn #$7E,#$7E    ; literal bank numbers; `mvn $7E,$7E` would mean bank $00
    phk
    plb               ; MVN left DBR = destination bank; restore for later reads
    cmp #$FFFF
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda f:$7E2100
    cmp #$11
    beq :+
    jmp @fail2
  :
    lda f:$7E2103
    cmp #$44
    beq :+
    jmp @fail3
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; MVN did not leave A = $FFFF
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; MVN did not copy the first byte
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
@fail3:
    ; MVN did not copy the last byte
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jmp test_restore
.endproc

; A8.02 — MVN sets DBR=dest
; provenance: Documented (SNESdev Errata, 65C816 section)
.proc test_a8_02
    .a16
    .i16
    ; After MVN $7E,$7E the data bank register is the destination bank ($7E), not $00.
    rep #$30
    .a16
    .i16
    ldx #$2000
    ldy #$2100
    lda #$0000        ; one byte
    mvn #$7E,#$7E    ; literal bank numbers; `mvn $7E,$7E` would mean bank $00
    phb
    sep #$20
    .a8
    pla
    cmp #$7E
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; MVN did not leave DBR = destination bank
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A8.03 — MVP copies backward
; provenance: Documented (WDC datasheet)
.proc test_a8_03
    .a16
    .i16
    ; MVP walks X and Y downward; point them at the LAST byte of each block.
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$AA
    sta f:$7E2200
    lda #$BB
    sta f:$7E2201
    rep #$30
    .a16
    .i16
    ldx #$2201
    ldy #$2301
    lda #$0001        ; two bytes
    mvp #$7E,#$7E    ; literal bank numbers; `mvp $7E,$7E` would mean bank $00
    phk
    plb
    sep #$20
    .a8
    lda f:$7E2300
    cmp #$AA
    beq :+
    jmp @fail1
  :
    lda f:$7E2301
    cmp #$BB
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; MVP did not copy the low byte
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; MVP did not copy the high byte
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; A9.01 — BIT imm vs abs
; provenance: Documented (WDC datasheet)
.proc test_a9_01
    .a16
    .i16
    ; BIT #imm must leave N and V untouched; BIT dp must set them from the operand.
    ; BIT has no long-addressing mode, so the operand is staged in the direct page
    ; (DP = $0000, so dp $50 is $00:0050, the low-WRAM mirror of $7E:0050).
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$C0
    sta f:$7E0050
    ; Clear N and V, then BIT #$00 — Z should set, N/V must stay clear.
    clv
    lda #$01
    bit #$00
    php
    pla
    and #$C0          ; N and V
    cmp #$00
    beq :+
    jmp @fail1
  :
    ; Now BIT dp against $C0 — both N and V must set.
    lda #$FF
    bit $50
    php
    pla
    and #$C0
    cmp #$C0
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; BIT #imm wrongly modified N or V
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; BIT dp did not set N and V from memory bits 7/6
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; A9.02 — XBA swaps A halves
; provenance: Documented (WDC datasheet)
.proc test_a9_02
    .a16
    .i16
    ; XBA is always a 16-bit operation on C, regardless of the m flag.
    rep #$30
    .a16
    .i16
    lda #$1234
    xba
    cmp #$3412
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; XBA did not swap the accumulator halves
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A1.06 — TCD/TDC always 16-bit
; provenance: Documented (WDC datasheet; SNESdev Wiki, 65C816)
.proc test_a1_06
    .a16
    .i16
    ; Set D with m=1, read it back with m=0. D is restored before the assertion because a
    ; failing path would otherwise leave every direct-page access in the battery relocated.
    rep #$30
    .a16
    .i16
    phk
    plb
    lda #$1234
    sep #$20          ; m=1: an 8-bit accumulator must not narrow the transfer
    .a8
    tcd
    rep #$20
    .a16
    tdc
    sta f:$7E0114
    lda #$0000
    tcd               ; restore D BEFORE asserting
    lda f:$7E0114
    cmp #$1234
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; TCD/TDC narrowed to 8 bits under m=1 (they are always 16-bit)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.07 — RMW abs,X is flat
; provenance: Documented (WDC datasheet; undisbeliever's timing tables)
.proc test_a5_07
    .a16
    .i16
    ; Same instruction, once without a page cross and once with. The index must be 8-BIT: a
    ; 16-bit index makes the penalty unconditional, which is what A5.02 establishes.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$10
    .i8
    ldx #$00
    jsr hv_begin
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    sep #$10
    .i8
    ldx #$FF          ; $1234 + $FF = $1333 — crosses into the next page
    jsr hv_begin
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    asl a:$1234,x
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sec
    sbc f:$7E0080
    cmp #$8000
    bcc :+
    eor #$FFFF
    inc a             ; negate: take the magnitude
  :
    cmp #$0003
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; RMW abs,X paid a page-cross penalty (its cost is flat)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A6.09 — BRK sets B in pushed P
; provenance: Documented (WDC datasheet; SNESdev Wiki, 65C816 interrupts)
.proc test_a6_09
    .a16
    .i16
    ; The handler recovers the pushed P through the stack. In emulation BRK pushes PCH, PCL,
    ; P — so P is the last byte written, at $01:(S+1), and TSX gives S's low byte.
    jmp @start
@handler:
    tsx
    lda a:$0101,x     ; the pushed status byte
    sta f:$7E009A
    rti
@start:
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler)
    sta a:V_BRK_VEC
    sep #$20
    .a8
    lda #$00
    sta f:$7E009A     ; poison, so a handler that never runs cannot pass
    sec
    xce               ; -> emulation
    .a8
    .i8
    brk
    .byte $EA
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    sep #$20
    .a8
    lda f:$7E009A
    and #$10
    cmp #$10
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; BRK did not set the B flag in the status byte it pushed
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; A5.08 — A5.22 cycle spot checks
; provenance: Documented (WDC/GTE/VLSI instruction-operation tables agree on these rows; docs/accuracysnes-timing-oracle.md)
.proc test_a5_08
    .a16
    .i16
    ; Differential against NOP, 16 repeats, so no span approaches the 341-dot line wrap.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    ; --- baseline: 16 NOPs ---
    jsr hv_begin
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0090
    ; record slot 0: 16 NOP, absolute
    sta f:$7EE200
    ; --- XBA: +6 clocks each over NOP, so +24 dots over 16 ---
    sep #$20
    .a8
    jsr hv_begin
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    xba
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 1: 16 XBA, absolute
    sta f:$7EE202
    sec
    sbc f:$7E0090
    ; record slot 2: 16 XBA - 16 NOP
    sta f:$7EE204
    cmp #$0016
    bcs :+
    jmp @fail1
  :
    cmp #$001B
    bcc :+
    jmp @fail1
  :
    ; --- REP #$00: 2 bytes, so +8 clocks each, +32 dots over 16. Emitted as raw bytes so the
    ; generator's width tracker is not told the accumulator changed size.
    sep #$20
    .a8
    jsr hv_begin
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    .byte $C2, $00   ; rep #$00
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 3: 16 REP #$00, absolute
    sta f:$7EE206
    sec
    sbc f:$7E0090
    ; record slot 4: 16 REP #$00 - 16 NOP
    sta f:$7EE208
    cmp #$001E
    bcs :+
    jmp @fail2
  :
    cmp #$0023
    bcc :+
    jmp @fail2
  :
    ; --- PHD+PLD: 30 + 36 = 66 clocks per pair against 2 NOPs at 28, so +76 dots over 8 ---
    sep #$20
    .a8
    jsr hv_begin
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    phd
    pld
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    ; record slot 5: 8x (PHD+PLD), absolute
    sta f:$7EE20A
    sec
    sbc f:$7E0090
    ; record slot 6: 8x (PHD+PLD) - 16 NOP
    sta f:$7EE20C
    cmp #$004A
    bcs :+
    jmp @fail3
  :
    cmp #$004F
    bcc :+
    jmp @fail3
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; XBA did not cost 3 cycles (1 more than NOP)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; REP #imm did not cost 3 cycles / 2 accesses
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
@fail3:
    ; PHD/PLD did not cost 4 and 5 cycles with 3 accesses each
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jmp test_restore
.endproc

; A9.03 — E=1 R-M-W modify write
; provenance: Contested (WDC note (17) asserts RWB is low during the modify cycle in emulation mode; the GTE and VLSI renderings of the same table are silent)
.proc test_a9_03
    .a16
    .i16
    ; Seed OAM words 0 and 1, aim the port at word 0, then do one R-M-W on $2104 in emulation
    ; mode. The OAM address counter afterwards reports how many writes actually happened.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    ; --- seed two words so a stray second write is visible, and clear the probe ---
    stz $2102
    stz $2103
    lda #$11
    sta $2104
    lda #$99       ; NOT $22 — see the collision note below
    sta $2104
    lda #$33
    sta $2104
    lda #$44
    sta $2104
    ; --- aim at word 0 and perform ONE read-modify-write on the data port ---
    stz $2102
    stz $2103
    sec
    xce               ; -> emulation
    .a8
    .i8
    inc a:$2104       ; R-M-W on the write-sensitive OAM data port
    clc
    xce               ; -> native (m/x stay 1: still 8-bit)
    .a8
    .i8
    ; --- how far did the address counter move? rewind and count back ---
    sep #$20
    .a8
    stz $2102
    stz $2103
    lda $2138
    sta f:$7E0130     ; byte 0 after the R-M-W
    lda $2138
    sta f:$7E0131     ; byte 1
    ; A single write advances the port by one byte; a modify-cycle write advances it by two.
    ; Byte 1 still holding its seed means one write; overwritten means two.
    lda f:$7E0131
    cmp #$99
    bne @two
    lda #$03          ; variant 1 = one write — the modify cycle did not write
    sta f:$7EE010
    jmp test_restore
@two:
    lda #$05          ; variant 2 = two writes — WDC note (17) holds
    sta f:$7EE010
    jmp test_restore
.endproc

; C1.01 — OAM word write/read
; provenance: Documented (SNESdev Wiki, OAM; fullsnes)
.proc test_c1_01
    .a16
    .i16
    ; OAMADDR is a WORD address. Two byte writes to $2104 fill one word, low byte first.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $2102         ; OAMADDR = word 0
    stz $2103
    lda #$AA
    sta $2104
    lda #$BB
    sta $2104         ; word 0 now committed
    stz $2102         ; rewind to word 0 to read it back
    stz $2103
    lda $2138
    cmp #$AA
    beq :+
    jmp @fail1
  :
    lda $2138
    cmp #$BB
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; OAM low byte did not read back
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; OAM high byte did not read back
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C1.02 — OAM odd write latched
; provenance: Documented (SNESdev Wiki, OAM; anomie)
.proc test_c1_02
    .a16
    .i16
    ; Seed word 1 with a known value, then write THREE bytes from word 0. The third byte is
    ; latched as the low half of word 1 and must not be committed on its own.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    ; --- seed word 1 = $EEDD ---
    lda #$01
    sta $2102         ; OAMADDR = word 1
    stz $2103
    lda #$DD
    sta $2104
    lda #$EE
    sta $2104
    ; --- three bytes starting at word 0 ---
    stz $2102
    stz $2103
    lda #$11
    sta $2104
    lda #$22
    sta $2104         ; word 0 committed
    lda #$33
    sta $2104         ; latched only — must NOT reach word 1
    ; --- read back ---
    stz $2102
    stz $2103
    lda $2138
    cmp #$11
    beq :+
    jmp @fail1
  :
    lda $2138
    cmp #$22
    beq :+
    jmp @fail2
  :
    lda $2138
    cmp #$DD
    beq :+
    jmp @fail3
  :
    lda $2138
    cmp #$EE
    beq :+
    jmp @fail4
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; word 0 low byte wrong
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; word 0 high byte wrong
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
@fail3:
    ; the odd trailing byte was committed (it must stay in the latch)
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jmp test_restore
@fail4:
    ; word 1 high byte was disturbed
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jmp test_restore
.endproc

; C1.03 — OAMADDR reload clears
; provenance: Documented (SNESdev Wiki, OAM; anomie)
.proc test_c1_03
    .a16
    .i16
    ; Write an odd byte count, then reload OAMADDR: the pending latch is discarded and the
    ; next pair starts cleanly rather than being offset by one byte.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$02
    sta $2102         ; word 2
    stz $2103
    lda #$99
    sta $2104         ; leave a byte pending in the latch
    lda #$02
    sta $2102         ; reload -> discard the pending byte
    stz $2103
    lda #$44
    sta $2104
    lda #$55
    sta $2104
    lda #$02
    sta $2102
    stz $2103
    lda $2138
    cmp #$44
    beq :+
    jmp @fail1
  :
    lda $2138
    cmp #$55
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; reloading OAMADDR did not discard the pending latch byte
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; word high byte wrong after OAMADDR reload
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C1.04 — OAM rd/wr one counter
; provenance: Documented (SNESdev Wiki, OAM)
.proc test_c1_04
    .a16
    .i16
    ; Write one word, then read one byte, then read again: the read pointer must have followed
    ; the write pointer rather than tracking separately.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$04
    sta $2102
    stz $2103
    lda #$5A
    sta $2104
    lda #$A5
    sta $2104
    lda #$7E
    sta $2104
    lda #$E7
    sta $2104         ; words 4 and 5 written
    lda #$05
    sta $2102         ; point at word 5 only
    stz $2103
    lda $2138
    cmp #$7E
    beq :+
    jmp @fail1
  :
    lda $2138
    cmp #$E7
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; shared counter: word 5 low byte wrong
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; shared counter: word 5 high byte wrong
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C1.05 — OAM high table mirror
; provenance: Documented (SNESdev Wiki, OAM; fullsnes)
.proc test_c1_05
    .a16
    .i16
    ; Write through the mirror at word $110 and read back at the real address, word $100.
    ; The high table commits per byte, so no write-twice pairing is involved.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$10
    sta $2102
    lda #$01          ; OAMADDR = word $110 (byte $220), bit 7 clear
    sta $2103
    lda #$5C
    sta $2104
    lda #$C5
    sta $2104
    ; --- read the real high-table bytes ---
    lda #$00
    sta $2102
    lda #$01          ; OAMADDR = word $100 (byte $200)
    sta $2103
    lda $2138
    cmp #$5C
    beq :+
    jmp @fail1
  :
    lda $2138
    cmp #$C5
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; OAM high table did not mirror: byte $220 -> $200
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; OAM high table did not mirror: byte $221 -> $201
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C2.01 — VMAIN step 1 word
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c2_01
    .a16
    .i16
    ; VMAIN=$80: step 1 word, increment after the HIGH byte. Three words written back to back
    ; must land at consecutive addresses.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$80
    sta $2115
    rep #$30
    .a16
    .i16
    ldx #$1000
    stx $2116
    lda #$1111
    sta $2118
    lda #$2222
    sta $2118
    lda #$3333
    sta $2118
    ; Read back word $1001. The first read after setting the address is the stale prefetch,
    ; so discard it and take the second (see C2.03).
    ldx #$1001
    stx $2116
    lda $2139         ; prefetch, discarded
    ldx #$1001
    stx $2116
    sep #$20
    .a8
    lda $2139
    cmp #$22
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; step-1 increment did not reach word $1001
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C2.02 — VMAIN low-byte trigger
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c2_02
    .a16
    .i16
    ; VMAIN=$00 increments after $2118 (the LOW byte), so writing only low bytes fills the low
    ; half of consecutive words and never touches the high halves. This is exactly how the
    ; runtime uploads its 1bpp font, so it is load-bearing here.
    rep #$30
    .a16
    .i16
    phk
    plb
    ; Clear two words first so the high bytes are known.
    sep #$20
    .a8
    lda #$80
    sta $2115
    rep #$30
    .a16
    .i16
    ldx #$1100
    stx $2116
    lda #$0000
    sta $2118
    sta $2118
    ; Now low-byte-only writes.
    sep #$20
    .a8
    stz $2115         ; VMAIN = $00: increment after the LOW byte
    rep #$30
    .a16
    .i16
    ldx #$1100
    stx $2116
    sep #$20
    .a8
    lda #$3C
    sta $2118
    lda #$C3
    sta $2118
    ; Read back word $1100: low $3C, high still 0.
    rep #$30
    .a16
    .i16
    ldx #$1100
    stx $2116
    lda $2139
    ldx #$1100
    stx $2116
    lda $2139
    cmp #$003C
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; low-byte-only write disturbed the high byte, or did not increment
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C2.03 — VRAM read prefetch
; provenance: Documented (SNESdev Wiki; docs/ppu.md edge case 4)
.proc test_c2_03
    .a16
    .i16
    ; Write two distinguishable words, then set the address and read TWICE. The first read is
    ; the prefetch latched when the address was written; the second is the real value.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$80
    sta $2115
    rep #$30
    .a16
    .i16
    ldx #$1200
    stx $2116
    lda #$ABCD
    sta $2118
    lda #$1234
    sta $2118         ; word $1200 = $ABCD, word $1201 = $1234
    ldx #$1200
    stx $2116
    lda $2139         ; prefetch of word $1200
    and #$FFFF
    cmp #$ABCD
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; the read after setting VMADD did not return word $1200
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C2.04 — VRAM bit 15 unconnected
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c2_04
    .a16
    .i16
    ; VRAM is 32K words, so a 16-bit word address has one bit too many. Bit 15 is unconnected,
    ; making $8xxx an alias of $0xxx rather than an out-of-range access.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$80
    sta $2115
    rep #$30
    .a16
    .i16
    ldx #$1300
    stx $2116
    lda #$BEEF
    sta $2118
    ; Read the same word through the mirrored address.
    ldx #$9300
    stx $2116
    lda $2139
    ldx #$9300
    stx $2116
    lda $2139
    cmp #$BEEF
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; VRAM address bit 15 was decoded (it must be unconnected)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C2.05 — VMAIN step 32 words
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c2_05
    .a16
    .i16
    ; Write with step=32, then read the far word back to confirm the stride.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$81          ; VMAIN: step 32 words, increment after the high byte
    sta $2115
    rep #$30
    .a16
    .i16
    ldx #$1400
    stx $2116
    lda #$0F0F
    sta $2118
    lda #$F0F0
    sta $2118         ; words $1400 and $1420
    ; Read word $1420 with the plain step so the address does not run away.
    sep #$20
    .a8
    lda #$80
    sta $2115
    rep #$30
    .a16
    .i16
    ldx #$1420
    stx $2116
    lda $2139
    ldx #$1420
    stx $2116
    lda $2139
    cmp #$F0F0
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; VMAIN step-32 increment did not land at word $1420
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C2.06 — VMAIN remap hits bus
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes; anomie)
.proc test_c2_06
    .a16
    .i16
    ; Two back-to-back writes with remap 01 active, then read both target words with remap off.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$84          ; VMAIN: remap 01 (8-bit), step 1, increment after the high byte
    sta $2115
    rep #$30
    .a16
    .i16
    ldx #$1503
    stx $2116
    lda #$CAFE
    sta $2118         ; register $1503 -> bus word $1518
    lda #$B0BA
    sta $2118         ; register $1504 -> bus word $1520
    ; --- read both back with translation off ---
    sep #$20
    .a8
    lda #$80
    sta $2115
    rep #$30
    .a16
    .i16
    ldx #$1518
    stx $2116
    lda $2139
    cmp #$CAFE
    beq :+
    jmp @fail1
  :
    ldx #$1520
    stx $2116
    lda $2139
    cmp #$B0BA
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; remap 01 did not translate register $1503 to bus word $1518
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; the remap fed back into the address register (the second write missed word $1520)
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C3.01 — CGRAM two-write commit
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c3_01
    .a16
    .i16
    ; $2122 is written twice per colour: low byte then high. Read back through $213B.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$10
    sta $2121         ; CGADD = colour 16
    lda #$34
    sta $2122
    lda #$12
    sta $2122         ; colour 16 = $1234
    lda #$10
    sta $2121
    lda $213B
    cmp #$34
    beq :+
    jmp @fail1
  :
    lda $213B
    and #$7F          ; bit 7 of the second read is PPU2 open bus
    cmp #$12
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; CGRAM low byte did not read back
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; CGRAM high byte did not read back
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C3.02 — CGADD resets flipflop
; provenance: Documented (SNESdev Wiki, PPU registers)
.proc test_c3_02
    .a16
    .i16
    ; Leave a byte pending, reload CGADD, then write a full colour: the pending byte must be
    ; discarded rather than pairing with the next write.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$11
    sta $2121
    lda #$99
    sta $2122         ; pending
    lda #$11
    sta $2121         ; reload -> flipflop reset
    lda #$78
    sta $2122
    lda #$56
    sta $2122
    lda #$11
    sta $2121
    lda $213B
    cmp #$78
    beq :+
    jmp @fail1
  :
    lda $213B
    and #$7F
    cmp #$56
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; CGADD write did not reset the flipflop
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; CGRAM high byte wrong after flipflop reset
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C3.03 — OPHCT is a 9-bit pair
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c3_03
    .a16
    .i16
    ; $213F resets the read flipflops, $2137 latches, then two $213C reads give low byte and
    ; (in bit 0 only) bit 8. Reconstructed, that must be a real position on the scanline.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda $213F         ; reset the OPHCT/OPVCT read flipflops
    lda $2137         ; latch H and V
    lda $213C         ; low 8 bits
    xba
    lda $213C
    and #$01          ; bit 0 is counter bit 8; bits 1-7 are open bus
    xba
    rep #$20
    .a16
    and #$01FF
    cmp #$0000
    bcs :+
    jmp @fail1
  :
    cmp #$0155
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; reconstructed H counter is outside a scanline
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C3.04 — H counter advances
; provenance: Documented (SNESdev Wiki, PPU registers)
.proc test_c3_04
    .a16
    .i16
    ; Latch, burn a known amount of time, latch again. The elapsed dot count must be non-zero
    ; and must not have wrapped past the end of the line.
    rep #$30
    .a16
    .i16
    phk
    plb
    jsr hv_begin
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; elapsed dots
    cmp #$0001
    bcs :+
    jmp @fail1
  :
    cmp #$0155
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; the H counter did not advance plausibly across 16 NOPs
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C3.05 — $213F resets flipflop
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c3_05
    .a16
    .i16
    ; Latch once, then read low / high / reset / low. Nothing re-latches in between, so the
    ; two low reads sample the same frozen value and any difference is a flipflop bug.
    rep #$30
    .a16
    .i16
    phk
    plb
    cld               ; the SBC below must not run in decimal mode
    sep #$20
    .a8
    lda $213F         ; reset both read flipflops
    lda $2137         ; latch H and V
    lda $213C         ; H low
    sta f:$7E0100
    lda $213C         ; H high — the flipflop is now set
    lda $213F         ; reset both flipflops again
    lda $213C         ; must be H low once more
    sec
    sbc f:$7E0100
    cmp #$00
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; $213F did not reset the OPHCT flipflop (the third read was not the low byte)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C13.01 — PPU1 open bus in $213E
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c13_01
    .a16
    .i16
    ; Drive PPU1 open bus to $10 via an OAM read, check $213E bit 4, then drive it to $00 and
    ; check again. Only bit 4 is examined: bits 7-6 are the sprite flags and 5-0 the version.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    ; --- open bus := $10 ---
    lda #$08
    sta $2102
    stz $2103
    lda #$10
    sta $2104
    lda #$00
    sta $2104
    lda #$08
    sta $2102
    stz $2103
    lda $2138         ; returns $10 and refreshes PPU1 open bus with it
    lda $213E
    and #$10
    cmp #$10
    beq :+
    jmp @fail1
  :
    ; --- open bus := $00 ---
    lda #$08
    sta $2102
    stz $2103
    lda #$00
    sta $2104
    lda #$00
    sta $2104
    lda #$08
    sta $2102
    stz $2103
    lda $2138         ; returns $00
    lda $213E
    and #$10
    cmp #$00
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; $213E bit 4 did not follow PPU1 open bus set to $10
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; $213E bit 4 did not follow PPU1 open bus cleared to $00
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C13.02 — PPU2 open bus in $213F
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c13_02
    .a16
    .i16
    ; Same shape as C13.01 but on the other chip: CGRAM reads go through PPU2, so a $213B read
    ; is what refreshes this latch.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    ; --- open bus := $20 ---
    lda #$20
    sta $2121
    lda #$20
    sta $2122
    lda #$00
    sta $2122
    lda #$20
    sta $2121
    lda $213B         ; returns $20 and refreshes PPU2 open bus with it
    lda $213F
    and #$20
    cmp #$20
    beq :+
    jmp @fail1
  :
    ; --- open bus := $00 ---
    lda #$20
    sta $2121
    lda #$00
    sta $2122
    lda #$00
    sta $2122
    lda #$20
    sta $2121
    lda $213B         ; returns $00
    lda $213F
    and #$20
    cmp #$00
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; $213F bit 5 did not follow PPU2 open bus set to $20
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; $213F bit 5 did not follow PPU2 open bus cleared to $00
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C13.03 — PPU1/PPU2 bus separate
; provenance: Corroborated (the bsnes/ares lineage and Mesen2 model two distinct latches)
.proc test_c13_03
    .a16
    .i16
    ; Drive the two latches to opposite values and read both back. Then swap and repeat, so a
    ; shared latch cannot pass by accident in one polarity.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    ; --- seed OAM byte $10 / $00 and CGRAM low byte $20 / $00 ---
    lda #$08
    sta $2102
    stz $2103
    lda #$10
    sta $2104
    lda #$00
    sta $2104         ; OAM word 8 = $0010
    ; Word 9 must be seeded too, not assumed zero: it is read below to drive PPU1 open bus to
    ; $00, and whatever the previous tests or the power-on fill left there would otherwise
    ; decide the result. Mesen2 and snes9x disagree on that leftover, which is not a hardware
    ; difference — it is this test failing to control its own inputs.
    lda #$00
    sta $2104
    lda #$00
    sta $2104         ; OAM word 9 = $0000
    lda #$20
    sta $2121
    lda #$20
    sta $2122
    lda #$00
    sta $2122         ; colour $20 = $0020
    lda #$00
    sta $2122
    lda #$00
    sta $2122         ; colour $21 = $0000, for the same reason as OAM word 9
    ; --- PPU1 := $10, PPU2 := $00 ---
    lda #$08
    sta $2102
    stz $2103
    lda $2138         ; PPU1 open bus := $10
    lda #$21
    sta $2121
    lda $213B         ; colour $21 low byte = $00; PPU2 open bus := $00
    lda $213E
    and #$10
    cmp #$10
    beq :+
    jmp @fail1
  :
    lda $213F
    and #$20
    cmp #$00
    beq :+
    jmp @fail2
  :
    ; --- PPU1 := $00, PPU2 := $20 ---
    lda #$09
    sta $2102
    stz $2103
    lda $2138         ; OAM word 9 is zero; PPU1 open bus := $00
    lda #$20
    sta $2121
    lda $213B         ; PPU2 open bus := $20
    lda $213E
    and #$10
    cmp #$00
    beq :+
    jmp @fail3
  :
    lda $213F
    and #$20
    cmp #$20
    beq :+
    jmp @fail4
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; refreshing PPU2 open bus clobbered PPU1's latch
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; PPU2 open bus read back as PPU1's value
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
@fail3:
    ; PPU1 open bus read back as PPU2's value
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jmp test_restore
@fail4:
    ; refreshing PPU1 open bus clobbered PPU2's latch
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jmp test_restore
.endproc

; C14.01 — PPU1 version (golden)
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c14_01
    .a16
    .i16
    ; Report the low nibble of $213E as the variant code.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda $213E
    and #$0F          ; PPU1 version
    asl a
    ora #$01          ; encode as (version << 1) | 1
    sta f:$7EE010
    jmp test_restore
.endproc

; C14.02 — PPU2 version (golden)
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c14_02
    .a16
    .i16
    ; Report the low nibble of $213F as the variant code.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda $213F
    and #$0F          ; PPU2 version
    asl a
    ora #$01
    sta f:$7EE010
    jmp test_restore
.endproc

; C11.06 — MPY is 16x8 signed
; provenance: Documented (SNESdev Wiki, Mode 7; fullsnes)
.proc test_c11_06
    .a16
    .i16
    ; Positive case: M7A = $0100 (256), M7B high byte = $02, so the product is 512 = $000200.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$00
    sta $211B         ; M7A low
    lda #$01
    sta $211B         ; M7A high -> M7A = $0100
    lda #$00
    sta $211C         ; M7B low (ignored by the multiply)
    lda #$02
    sta $211C         ; M7B high -> multiplicand = +2
    lda $2134
    cmp #$00
    beq :+
    jmp @fail1
  :
    lda $2135
    cmp #$02
    beq :+
    jmp @fail2
  :
    lda $2136
    cmp #$00
    beq :+
    jmp @fail3
  :
    ; The low byte of M7B must not participate: rewriting it alone cannot change the product.
    lda #$FF
    sta $211C         ; M7B low = $FF
    lda #$02
    sta $211C         ; M7B high still $02
    lda $2135
    cmp #$02
    beq :+
    jmp @fail4
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; MPYL wrong for 256 * 2
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; MPYM wrong for 256 * 2
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
@fail3:
    ; MPYH wrong for 256 * 2
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jmp test_restore
@fail4:
    ; the low byte of M7B leaked into the multiply
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jmp test_restore
.endproc

; C11.06b — MPY sign handling
; provenance: Documented (SNESdev Wiki, Mode 7; fullsnes)
.proc test_c11_06b
    .a16
    .i16
    ; Negative multiplicand: M7A = $0002, M7B high = $FF (-1) -> -2 = $FFFFFE.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$02
    sta $211B
    lda #$00
    sta $211B         ; M7A = $0002
    lda #$00
    sta $211C
    lda #$FF
    sta $211C         ; multiplicand = -1
    lda $2134
    cmp #$FE
    beq :+
    jmp @fail1
  :
    lda $2135
    cmp #$FF
    beq :+
    jmp @fail2
  :
    lda $2136
    cmp #$FF
    beq :+
    jmp @fail3
  :
    ; Negative multiplier: M7A = $FFFF (-1), M7B high = $02 -> -2 = $FFFFFE.
    lda #$FF
    sta $211B
    lda #$FF
    sta $211B         ; M7A = $FFFF
    lda #$00
    sta $211C
    lda #$02
    sta $211C
    lda $2134
    cmp #$FE
    beq :+
    jmp @fail4
  :
    lda $2136
    cmp #$FF
    beq :+
    jmp @fail5
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; MPYL wrong for 2 * -1 (M7B high must be signed)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; MPYM wrong for 2 * -1
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
@fail3:
    ; the product did not sign-extend to 24 bits
    sep #$20
    .a8
    lda #$06
    sta f:$7EE010
    jmp test_restore
@fail4:
    ; MPYL wrong for -1 * 2 (M7A must be signed)
    sep #$20
    .a8
    lda #$08
    sta f:$7EE010
    jmp test_restore
@fail5:
    ; the product did not sign-extend for a negative M7A
    sep #$20
    .a8
    lda #$0A
    sta f:$7EE010
    jmp test_restore
.endproc

; C7.01 — Range Over at 32 sprites
; provenance: Documented (SNESdev Wiki, Sprites; fullsnes)
.proc test_c7_01
    .a16
    .i16
    rep #$30
    .a16
    .i16
    phk
    plb
    ; --- 2 sprites on the line: well under the limit, flag must stay clear ---
    sep #$20
    .a8
    lda #$00
    sta $2101         ; OBJSEL: size pair in bits 7-5, name base in bits 1-0
    ; --- low table: `on_line` sprites on one scanline, the rest parked off-screen ---
    stz $2102
    stz $2103
    rep #$10
    .i16
    ldx #$0000
@fill_a:
    lda #$00
    sta $2104         ; X = 0
    cpx #$0002
    bcs @off_a
    lda #100
    bra @sety_a
@off_a:
    lda #$F0          ; below the visible area in 224-line mode
@sety_a:
    sta $2104         ; Y
    lda #$00
    sta $2104         ; tile
    lda #$00
    sta $2104         ; attr
    inx
    cpx #$0080
    bne @fill_a
    ; --- high table: 32 bytes, 2 bits per sprite (bit 0 = X bit 8, bit 1 = size select) ---
    lda #$00
    sta $2102
    lda #$01
    sta $2103         ; OAMADDR = word $100, the high table
    ldx #$0000
@hi_a:
    lda #$00
    sta $2104
    inx
    cpx #$0020
    bne @hi_a
    ; --- render one complete frame, then sample and restore forced blank ---
    lda #$10
    sta $212C         ; OBJ on the main screen
    lda #$0F
    sta $2100         ; brightness 15, forced blank released
    jsr wait_vblank   ; land on a vblank boundary
    jsr wait_vblank   ; span one complete active period
    lda $213E
    pha
    lda #$8F
    sta $2100         ; forced blank again, as the rest of the battery expects
    stz $212C
    pla
    and #$40
    cmp #$00
    beq :+
    jmp @fail1
  :
    ; --- 40 sprites on the line: over the 32-sprite limit ---
    rep #$30
    .a16
    .i16
    sep #$20
    .a8
    lda #$00
    sta $2101         ; OBJSEL: size pair in bits 7-5, name base in bits 1-0
    ; --- low table: `on_line` sprites on one scanline, the rest parked off-screen ---
    stz $2102
    stz $2103
    rep #$10
    .i16
    ldx #$0000
@fill_b:
    lda #$00
    sta $2104         ; X = 0
    cpx #$0028
    bcs @off_b
    lda #100
    bra @sety_b
@off_b:
    lda #$F0          ; below the visible area in 224-line mode
@sety_b:
    sta $2104         ; Y
    lda #$00
    sta $2104         ; tile
    lda #$00
    sta $2104         ; attr
    inx
    cpx #$0080
    bne @fill_b
    ; --- high table: 32 bytes, 2 bits per sprite (bit 0 = X bit 8, bit 1 = size select) ---
    lda #$00
    sta $2102
    lda #$01
    sta $2103         ; OAMADDR = word $100, the high table
    ldx #$0000
@hi_b:
    lda #$00
    sta $2104
    inx
    cpx #$0020
    bne @hi_b
    ; --- render one complete frame, then sample and restore forced blank ---
    lda #$10
    sta $212C         ; OBJ on the main screen
    lda #$0F
    sta $2100         ; brightness 15, forced blank released
    jsr wait_vblank   ; land on a vblank boundary
    jsr wait_vblank   ; span one complete active period
    lda $213E
    pha
    lda #$8F
    sta $2100         ; forced blank again, as the rest of the battery expects
    stz $212C
    pla
    and #$40
    cmp #$40
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; Range Over set with only 2 sprites on the scanline
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; Range Over did not set with 40 sprites on one scanline
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C7.02 — Time Over is slivers
; provenance: Documented (SNESdev Wiki, Sprites; fullsnes; anomie)
.proc test_c7_02
    .a16
    .i16
    ; OBJSEL size select lives in bits 7-5, not the low bits: mode 2 ($40) pairs 8x8 with
    ; 64x64, and the high table marks sprites 0-4 as the large member of that pair. Writing
    ; the mode number into the low bits instead sets the tile-name base and silently leaves
    ; the size pair at 8x8/16x16 — 10 slivers, comfortably inside the budget, no flag.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$40
    sta $2101         ; OBJSEL: size pair in bits 7-5, name base in bits 1-0
    ; --- low table: `on_line` sprites on one scanline, the rest parked off-screen ---
    stz $2102
    stz $2103
    rep #$10
    .i16
    ldx #$0000
@fill_a:
    lda #$00
    sta $2104         ; X = 0
    cpx #$0005
    bcs @off_a
    lda #100
    bra @sety_a
@off_a:
    lda #$F0          ; below the visible area in 224-line mode
@sety_a:
    sta $2104         ; Y
    lda #$00
    sta $2104         ; tile
    lda #$00
    sta $2104         ; attr
    inx
    cpx #$0080
    bne @fill_a
    ; --- high table: 32 bytes, 2 bits per sprite (bit 0 = X bit 8, bit 1 = size select) ---
    lda #$00
    sta $2102
    lda #$01
    sta $2103         ; OAMADDR = word $100, the high table
    ldx #$0000
@hi_a:
    lda #$00
    sta $2104
    inx
    cpx #$0020
    bne @hi_a
    ; Mark the leading sprites as the large size of the pair.
    lda #$00
    sta $2102
    lda #$01
    sta $2103
    lda #$AA
    sta $2104
    lda #$02
    sta $2104
    ; --- render one complete frame, then sample and restore forced blank ---
    lda #$10
    sta $212C         ; OBJ on the main screen
    lda #$0F
    sta $2100         ; brightness 15, forced blank released
    jsr wait_vblank   ; land on a vblank boundary
    jsr wait_vblank   ; span one complete active period
    lda $213E
    pha
    lda #$8F
    sta $2100         ; forced blank again, as the rest of the battery expects
    stz $212C
    pla
    pha
    and #$80
    cmp #$80
    beq :+
    jmp @fail1
  :
    pla
    and #$40
    cmp #$00
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; Time Over did not set for 40 slivers from 5 sprites
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; Range Over set for only 5 sprites (it is a sprite count, not a sliver count)
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C7.08 — Flags ignore $212C
; provenance: Documented (SNESdev Wiki, Sprites; fullsnes)
.proc test_c7_08
    .a16
    .i16
    ; Same 40-sprite overflow as C7.01, but with OBJ left off the main screen entirely.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$00
    sta $2101         ; OBJSEL: size pair in bits 7-5, name base in bits 1-0
    ; --- low table: `on_line` sprites on one scanline, the rest parked off-screen ---
    stz $2102
    stz $2103
    rep #$10
    .i16
    ldx #$0000
@fill_a:
    lda #$00
    sta $2104         ; X = 0
    cpx #$0028
    bcs @off_a
    lda #100
    bra @sety_a
@off_a:
    lda #$F0          ; below the visible area in 224-line mode
@sety_a:
    sta $2104         ; Y
    lda #$00
    sta $2104         ; tile
    lda #$00
    sta $2104         ; attr
    inx
    cpx #$0080
    bne @fill_a
    ; --- high table: 32 bytes, 2 bits per sprite (bit 0 = X bit 8, bit 1 = size select) ---
    lda #$00
    sta $2102
    lda #$01
    sta $2103         ; OAMADDR = word $100, the high table
    ldx #$0000
@hi_a:
    lda #$00
    sta $2104
    inx
    cpx #$0020
    bne @hi_a
    ; --- render one complete frame, then sample and restore forced blank ---
    stz $212C         ; deliberately leave OBJ OFF the main screen
    lda #$0F
    sta $2100         ; brightness 15, forced blank released
    jsr wait_vblank   ; land on a vblank boundary
    jsr wait_vblank   ; span one complete active period
    lda $213E
    pha
    lda #$8F
    sta $2100         ; forced blank again, as the rest of the battery expects
    stz $212C
    pla
    and #$40
    cmp #$40
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; Range Over did not set while OBJ was off the main screen ($212C gates compositing, not evaluation)
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C2.11 — VRAM locked in render
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes)
.proc test_c2_11
    .a16
    .i16
    ; Clear three words under forced blank, then try to write two of them from active display.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$80
    sta $2115         ; VMAIN step 1, increment after the high byte
    rep #$30
    .a16
    .i16
    ldx #$1600
    stx $2116
    lda #$0000
    sta $2118
    sta $2118
    sta $2118         ; words $1600-$1602 cleared
    ldx #$1600
    stx $2116         ; aim at $1600 before the window closes
    sep #$20
    .a8
    lda #$0F
    sta $2100         ; forced blank off — the access window now depends on position
    jsr wait_vblank
    jsr wait_vblank   ; a full settled frame
@wa_c211:
    lda $4212
    and #$80
    bne @wa_c211   ; wait for vblank to end
    rep #$10
    .i16
    ldx #$0400
@burn_c211:
    dex
    bne @burn_c211 ; ~20 scanlines in, well clear of the pre-render line
    rep #$20
    .a16
    lda #$AAAA
    sta $2118         ; must be dropped
    sta $2118         ; must be dropped
    sep #$20
    .a8
    lda #$8F
    sta $2100         ; forced blank restored
    ; --- read back: both words must still be zero ---
    rep #$30
    .a16
    .i16
    ldx #$1600
    stx $2116
    lda $2139
    cmp #$0000
    beq :+
    jmp @fail1
  :
    ldx #$1601
    stx $2116
    lda $2139
    cmp #$0000
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; a VRAM write during active display was not dropped
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; the second VRAM write during active display was not dropped
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C2.10 — Dropped write still incs
; provenance: Documented (SNESdev Wiki, PPU registers; fullsnes; anomie)
.proc test_c2_10
    .a16
    .i16
    ; Same shape as C2.11, but the payload is the write that follows: if the two dropped writes
    ; advanced the address, the legal third write lands at $1602 rather than back at $1600.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    lda #$80
    sta $2115
    rep #$30
    .a16
    .i16
    ldx #$1610
    stx $2116
    lda #$0000
    sta $2118
    sta $2118
    sta $2118         ; words $1610-$1612 cleared
    ldx #$1610
    stx $2116
    sep #$20
    .a8
    lda #$0F
    sta $2100         ; forced blank off — the access window now depends on position
    jsr wait_vblank
    jsr wait_vblank   ; a full settled frame
@wa_c210:
    lda $4212
    and #$80
    bne @wa_c210   ; wait for vblank to end
    rep #$10
    .i16
    ldx #$0400
@burn_c210:
    dex
    bne @burn_c210 ; ~20 scanlines in, well clear of the pre-render line
    rep #$20
    .a16
    lda #$AAAA
    sta $2118         ; dropped, but the address must advance to $1611
    sta $2118         ; dropped, but the address must advance to $1612
    sep #$20
    .a8
    lda #$8F
    sta $2100         ; forced blank: the window is open again
    rep #$20
    .a16
    lda #$BBBB
    sta $2118         ; this one must land, and at $1612
    ; --- read back ---
    rep #$30
    .a16
    .i16
    ldx #$1612
    stx $2116
    lda $2139
    cmp #$BBBB
    beq :+
    jmp @fail1
  :
    ldx #$1610
    stx $2116
    lda $2139
    cmp #$0000
    beq :+
    jmp @fail2
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; the address did not advance across the dropped writes
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; the legal write landed at $1610 instead of $1612
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; C1.06 — OAM addr reloads
; provenance: Documented (SNESdev Wiki, OAM; anomie)
.proc test_c1_06
    .a16
    .i16
    ; Seed three words, set the base to word 0, then walk the internal address forward to word
    ; 2. After a rendered frame the next read must come from word 0 again.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $2102
    stz $2103
    lda #$11
    sta $2104
    lda #$22
    sta $2104         ; word 0
    lda #$33
    sta $2104
    lda #$44
    sta $2104         ; word 1
    lda #$55
    sta $2104
    lda #$66
    sta $2104         ; word 2
    ; --- base = word 0, then advance the internal counter to word 2 by reading ---
    stz $2102
    stz $2103
    lda $2138
    lda $2138
    lda $2138
    lda $2138         ; internal address now word 2
    ; --- render one complete frame; the reload happens as vblank begins ---
    lda #$0F
    sta $2100
    jsr wait_vblank
    jsr wait_vblank
    lda $2138         ; read while forced blank is still off
    sta f:$7E0102
    lda #$8F
    sta $2100
    lda f:$7E0102
    cmp #$11
    beq :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; the OAM address did not reload from its base across a frame
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

; C9.04 — Overscan moves vblank
; provenance: Documented (SNESdev Wiki, Timing; fullsnes)
.proc test_c9_04
    .a16
    .i16
    ; Sample the V counter at the instant vblank begins, with overscan off and then on. Both
    ; samples take two wait_vblank calls so the setting has been stable for a whole frame —
    ; toggling $2133 mid-frame is its own documented hazard and is not what this measures.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $2133         ; overscan off: 224 visible lines
    jsr wait_vblank
    jsr wait_vblank
    lda $213F         ; reset the counter read flipflops
    lda $2137         ; latch H and V
    lda $213D         ; V low
    xba
    lda $213D
    and #$01          ; bit 0 is V bit 8; bits 1-7 are PPU2 open bus
    xba
    rep #$20
    .a16
    and #$01FF
    cmp #$00E1
    bcs :+
    jmp @fail1
  :
    cmp #$00E9
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$04
    sta $2133         ; overscan on: 239 visible lines
    jsr wait_vblank
    jsr wait_vblank
    lda $213F
    lda $2137
    lda $213D
    xba
    lda $213D
    and #$01
    xba
    rep #$20
    .a16
    and #$01FF
    cmp #$00F0
    bcs :+
    jmp @fail2
  :
    cmp #$00F8
    bcc :+
    jmp @fail2
  :
    sep #$20
    .a8
    stz $2133         ; restore
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; vblank did not begin near line 225 without overscan
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
@fail2:
    ; overscan did not move the start of vblank to line 240
    sep #$20
    .a8
    lda #$04
    sta f:$7EE010
    jmp test_restore
.endproc

; B1.01 — MEMSEL selects FastROM
; provenance: Documented (SNESdev Wiki, Memory map / timing; fullsnes)
.proc test_b1_01
    .a16
    .i16
    ; 32 long reads from bank $80, once slow and once fast. 2 master clocks saved per access
    ; over 32 accesses is 64 clocks = 16 dots, comfortably outside the measurement jitter.
    rep #$30
    .a16
    .i16
    phk
    plb
    sep #$20
    .a8
    stz $420D         ; MEMSEL = 0: banks $80+ run at 8 clocks
    jsr hv_begin
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
