    lda f:$808000
    lda f:$808000
    jsr hv_end
    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0080
    sep #$20
    .a8
    lda #$01
    sta $420D         ; MEMSEL = 1: FastROM, 6 clocks
    jsr hv_begin
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
    lda f:$808000
