    rep #$30
    .a16
    .i16
    lda f:$7E0048     ; V_H1 = elapsed dots
    sta f:$7E0082
    ; Restore the slow default before asserting — a failing path exits immediately.
    sep #$20
    .a8
    stz $420D
    rep #$20
    .a16
    lda f:$7E0080
    sec
    sbc f:$7E0082     ; slow - fast, so a working FastROM is positive
    cmp #$000E
    bcs :+
    jmp @fail1
  :
    cmp #$0013
    bcc :+
    jmp @fail1
