    sta f:$7EE298
    sep #$20
    .a8
    stz $4200
    lda $4211
    rep #$20
    .a16
    lda f:$7E012C
    cmp #$0096
    bcs :+
    jmp @fail1
  :
    cmp #$0099
    bcc :+
    jmp @fail1
  :
    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
